import{_ as r,o as l,c as d,a2 as n}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"玻璃基板台股供應鏈深度分析","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/玻璃基板研究/玻璃基板_台股供應鏈.md","filePath":"Deep32Q知識庫/產業洞察/玻璃基板研究/玻璃基板_台股供應鏈.md"}'),o={name:"Deep32Q知識庫/產業洞察/玻璃基板研究/玻璃基板_台股供應鏈.md"};function s(e,t,i,a,g,h){return l(),d("div",null,[...t[0]||(t[0]=[n('<h1 id="玻璃基板台股供應鏈深度分析" tabindex="-1">玻璃基板台股供應鏈深度分析 <a class="header-anchor" href="#玻璃基板台股供應鏈深度分析" aria-label="Permalink to &quot;玻璃基板台股供應鏈深度分析&quot;">​</a></h1><p><strong>研究日期</strong>：2026-05-05 <strong>分析範圍</strong>：逐家台廠供應鏈定位、技術優勢、營收貢獻度預估</p><hr><h2 id="一、台股概念股總覽" tabindex="-1">一、台股概念股總覽 <a class="header-anchor" href="#一、台股概念股總覽" aria-label="Permalink to &quot;一、台股概念股總覽&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">股號</th><th>公司</th><th>供應鏈位置</th><th>玻璃基板相關性</th><th>關鍵進展（2026年5月）</th></tr></thead><tbody><tr><td style="text-align:center;">1802</td><td>台玻</td><td>材料端</td><td>⭐⭐⭐⭐⭐</td><td>電子級玻纖布切入 NVIDIA GB200，2026 高階產線擴產 40-50%</td></tr><tr><td style="text-align:center;">3037</td><td>欣興</td><td>載板製造</td><td>⭐⭐⭐⭐⭐</td><td>2026 Q3 樣品驗證，年底裝機，量產最快 2027-2028</td></tr><tr><td style="text-align:center;">8046</td><td>南電</td><td>載板製造</td><td>⭐⭐⭐⭐</td><td>ABF/BT 載板產能滿載，T-Glass 強化現有載板</td></tr><tr><td style="text-align:center;">3189</td><td>景碩</td><td>載板製造</td><td>⭐⭐⭐⭐</td><td>美系 GPU 客戶供應鏈，楊梅六廠 ABF 產能 2027 年開出</td></tr><tr><td style="text-align:center;">8027</td><td>鈦昇</td><td>設備端</td><td>⭐⭐⭐⭐⭐</td><td>Intel 指定 TGV 雷射改質設備供應商，2026 Q3 新廠啟用</td></tr><tr><td style="text-align:center;">6664</td><td>群翊</td><td>設備端</td><td>⭐⭐⭐⭐⭐</td><td>塗佈/壓膜/烘烤設備通過國際 Tier1 OSAT 驗證，2026 關鍵年</td></tr><tr><td style="text-align:center;">6405</td><td>悅城</td><td>設備端</td><td>⭐⭐⭐</td><td>玻璃基板薄化/拋光/鍍膜，2025 已淡出玻璃加工轉型氮化鋁陶瓷</td></tr><tr><td style="text-align:center;">3711</td><td>日月光投控</td><td>封測</td><td>⭐⭐⭐</td><td>先進封裝經驗豐富，可望切入玻璃基板封裝產線</td></tr><tr><td style="text-align:center;">3481</td><td>群創</td><td>FOPLP</td><td>⭐⭐⭐⭐</td><td>G3.5 級最大 FOPLP 面板，2025 年開始量產出貨</td></tr><tr><td style="text-align:center;">2409</td><td>友達</td><td>FOPLP</td><td>⭐⭐⭐</td><td>面板製造經驗轉型 FOPLP，與玻璃基板融合中</td></tr><tr><td style="text-align:center;">2330</td><td>台積電</td><td>晶圓代工</td><td>⭐⭐⭐⭐⭐</td><td>CoPoS 技術，2026 年建迷你產線，目標 2028 年量產</td></tr></tbody></table><hr><h2 id="二、逐家深度分析" tabindex="-1">二、逐家深度分析 <a class="header-anchor" href="#二、逐家深度分析" aria-label="Permalink to &quot;二、逐家深度分析&quot;">​</a></h2><h3 id="_2-1-台玻-1802-—-材料端龍頭-⭐⭐⭐⭐⭐" tabindex="-1">2.1 台玻（1802）— 材料端龍頭 ⭐⭐⭐⭐⭐ <a class="header-anchor" href="#_2-1-台玻-1802-—-材料端龍頭-⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;2.1 台玻（1802）— 材料端龍頭 ⭐⭐⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：電子級玻纖布供應商，玻璃基板上游材料核心角色</p><p><strong>技術優勢</strong>：</p><ul><li>已量產低 DK、低 CTE 電子級玻纖布，性能接近日東紡 T-Glass</li><li>產品已正式切入 <strong>NVIDIA GB200 供應鏈</strong>，驗證通過</li></ul><p><strong>產能規劃</strong>：</p><ul><li>2026 年開出新產線，高階玻纖布供貨量較 2025 年增加 <strong>40-50%</strong></li><li>目標在 2027 年前達到日東紡 specialty fiber 產能的 <strong>20%</strong></li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板相關材料佔台玻總營收約 <strong>3-5%</strong>（目前以傳統玻纖為主）</li><li>隨著 AI 伺服器需求持續強勁，預估 2027 年可提升至 <strong>8-12%</strong></li></ul><p><strong>風險</strong>：</p><ul><li>高階 T-Glass 技術仍落後日東紡約 1-2 代</li><li>良率穩定性與長期可靠性驗證仍需時間</li></ul><hr><h3 id="_2-2-欣興-3037-—-載板製造龍頭-⭐⭐⭐⭐⭐" tabindex="-1">2.2 欣興（3037）— 載板製造龍頭 ⭐⭐⭐⭐⭐ <a class="header-anchor" href="#_2-2-欣興-3037-—-載板製造龍頭-⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;2.2 欣興（3037）— 載板製造龍頭 ⭐⭐⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：全球 ABF 載板龍頭，玻璃基板研發最積極的載板廠</p><p><strong>技術優勢</strong>：</p><ul><li>2026 年 3 月進行樣品驗證，年底裝機</li><li>量產時間最快落在 <strong>2027-2028 年</strong></li><li>AI 晶片尺寸增大及層數增加，高階載板產能吃緊</li></ul><p><strong>客戶結構</strong>：</p><ul><li>Intel 研發夥伴（歷史合作深厚）</li><li>2026 年已與 NVIDIA 及各大 CSP 廠展開協同開發</li><li>核心載板關鍵角色</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板相關訂單佔總營收約 <strong>5-8%</strong>（以樣品驗證和小量試產計）</li><li>2027-2028 年量產後，預估可提升至 <strong>15-25%</strong></li></ul><p><strong>風險</strong>：</p><ul><li>量產時程可能因良率問題延後</li><li>中國載板廠（如深南電）的競爭壓力</li></ul><hr><h3 id="_2-3-南電-8046-—-abf-載板大廠-⭐⭐⭐⭐" tabindex="-1">2.3 南電（8046）— ABF 載板大廠 ⭐⭐⭐⭐ <a class="header-anchor" href="#_2-3-南電-8046-—-abf-載板大廠-⭐⭐⭐⭐" aria-label="Permalink to &quot;2.3 南電（8046）— ABF 載板大廠 ⭐⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：ABF 載板重要供應商，玻璃基板技術積極布局中</p><p><strong>技術優勢</strong>：</p><ul><li>現有 ABF/BT 載板產能利用率維持高檔（AI 伺服器 + 800G 交換器 + ASIC）</li><li>T-Glass 玻纖布主要用於強化現有 ABF/BT 載板性能（非玻璃基板本身）</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板直接相關佔比約 <strong>3-5%</strong>（目前以 ABF/BT 載板為主）</li><li>受惠於 AI 伺服器需求，2026 年整體營收預期強勁</li></ul><p><strong>風險</strong>：</p><ul><li>玻璃基板直接布局進度不如欣興明確</li><li>T-Glass 短缺可能影響現有 ABF 載板產能</li></ul><hr><h3 id="_2-4-景碩-3189-—-bt-abf-載板雙強-⭐⭐⭐⭐" tabindex="-1">2.4 景碩（3189）— BT/ABF 載板雙強 ⭐⭐⭐⭐ <a class="header-anchor" href="#_2-4-景碩-3189-—-bt-abf-載板雙強-⭐⭐⭐⭐" aria-label="Permalink to &quot;2.4 景碩（3189）— BT/ABF 載板雙強 ⭐⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：BT 載板龍頭，美系 GPU 客戶供應鏈重要角色</p><p><strong>技術優勢</strong>：</p><ul><li>在美系 GPU 客戶（含 NVIDIA）供應鏈中扮演重要角色</li><li>正布局玻璃基板樣品驗證，預計 <strong>2026 底 - 2028 年</strong>開出產能</li><li>楊梅六廠 ABF 新產能預計於 <strong>2027 年開出</strong></li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板相關佔比約 <strong>3-5%</strong>（目前以 BT/ABF 載板為主）</li><li>2026-2027 年整體獲利預期高速成長</li></ul><p><strong>風險</strong>：</p><ul><li>玻璃基板量產時程較晚，短期營收貢獻有限</li></ul><hr><h3 id="_2-5-鈦昇-8027-—-tgv-雷射設備龍頭-⭐⭐⭐⭐⭐" tabindex="-1">2.5 鈦昇（8027）— TGV 雷射設備龍頭 ⭐⭐⭐⭐⭐ <a class="header-anchor" href="#_2-5-鈦昇-8027-—-tgv-雷射設備龍頭-⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;2.5 鈦昇（8027）— TGV 雷射設備龍頭 ⭐⭐⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：台灣玻璃基板設備領域指標公司，TGV 雷射改質設備專家</p><p><strong>技術優勢</strong>：</p><ul><li><strong>Intel 指定 TGV 雷射改質設備供應商</strong>，客戶關係牢固</li><li>訂單能見度已達 <strong>2026 Q3</strong></li><li>橋科園區新廠預計於 <strong>2026 年第三季啟用</strong>，產能提升 <strong>1.8 倍</strong></li><li>已組建「E-Core System 大聯盟」，預期 2026 年實現玻璃基板小量出貨</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板相關設備佔總營收約 <strong>15-25%</strong>（目前半導體設備為主）</li><li>隨 2026 Q3 新廠啟用，預估 2027 年可提升至 <strong>30-40%</strong></li></ul><p><strong>風險</strong>：</p><ul><li>設備出貨集中於少數大廠（Intel、TSMC），客戶集中度風險</li></ul><hr><h3 id="_2-6-群翊-6664-—-塗佈-壓膜-烘烤設備-⭐⭐⭐⭐⭐" tabindex="-1">2.6 群翊（6664）— 塗佈/壓膜/烘烤設備 ⭐⭐⭐⭐⭐ <a class="header-anchor" href="#_2-6-群翊-6664-—-塗佈-壓膜-烘烤設備-⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;2.6 群翊（6664）— 塗佈/壓膜/烘烤設備 ⭐⭐⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：PCB 塗佈、壓膜、乾燥設備供應商，深耕 FOPLP 與 TGV 玻璃基板製程</p><p><strong>技術優勢</strong>：</p><ul><li>設備已通過國際 Tier1 OSAT 驗證出貨</li><li><strong>2026 年為玻璃基板產業化關鍵年</strong></li><li>已提前布局玻璃基板與高階封裝所需的乾式製程設備</li><li>訂單能見度已達年底</li><li>楊梅二廠擴建計畫預計 <strong>2026 年底動工</strong>，<strong>2027 年底完工投產</strong>，增加 <strong>20-40%</strong> 產能</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板相關設備佔總營收約 <strong>10-20%</strong>（目前 PCB 設備為主）</li><li>2026-2027 年可望進入收成期</li></ul><p><strong>風險</strong>：</p><ul><li>玻璃基板設備市場規模尚小，短期營收貢獻有限</li></ul><hr><h3 id="_2-7-悅城-6405-—-薄化-拋光-鍍膜-⭐⭐⭐" tabindex="-1">2.7 悅城（6405）— 薄化/拋光/鍍膜 ⭐⭐⭐ <a class="header-anchor" href="#_2-7-悅城-6405-—-薄化-拋光-鍍膜-⭐⭐⭐" aria-label="Permalink to &quot;2.7 悅城（6405）— 薄化/拋光/鍍膜 ⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：玻璃基板薄化、拋光、鍍膜製程服務商</p><p><strong>技術優勢</strong>：</p><ul><li>已切入 3D 封裝領域，具備玻璃基板薄化關鍵製程能力</li></ul><p><strong>重要更新</strong>：</p><ul><li>⚠️ <strong>2025 年已淡出玻璃加工，轉型開發先進封裝所需的氮化鋁陶瓷基板</strong></li><li>目前玻璃基板相關業務已大幅縮減</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板直接相關佔比 <strong>&lt;1%</strong>（已轉型）</li></ul><p><strong>風險</strong>：</p><ul><li>玻璃基板業務已非主力，投資價值大幅下降</li></ul><hr><h3 id="_2-8-日月光投控-3711-—-封測龍頭-⭐⭐⭐" tabindex="-1">2.8 日月光投控（3711）— 封測龍頭 ⭐⭐⭐ <a class="header-anchor" href="#_2-8-日月光投控-3711-—-封測龍頭-⭐⭐⭐" aria-label="Permalink to &quot;2.8 日月光投控（3711）— 封測龍頭 ⭐⭐⭐&quot;">​</a></h3><p><strong>定位</strong>：全球最大 OSAT，先進封裝經驗豐富</p><p><strong>技術優勢</strong>：</p><ul><li>先進封裝（2.5D/3D）經驗豐富，可望切入玻璃基板封裝產線</li><li>與各大晶圓廠、系統廠合作關係深厚</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板封裝佔比約 <strong>2-3%</strong>（目前以傳統封裝為主）</li><li>隨玻璃基板量產，2027-2028 年可提升至 <strong>5-10%</strong></li></ul><hr><h3 id="_2-9-群創-3481-友達-2409-—-foplp-轉型-⭐⭐⭐-⭐⭐⭐⭐" tabindex="-1">2.9 群創（3481）/ 友達（2409）— FOPLP 轉型 ⭐⭐⭐~⭐⭐⭐⭐ <a class="header-anchor" href="#_2-9-群創-3481-友達-2409-—-foplp-轉型-⭐⭐⭐-⭐⭐⭐⭐" aria-label="Permalink to &quot;2.9 群創（3481）/ 友達（2409）— FOPLP 轉型 ⭐⭐⭐~⭐⭐⭐⭐&quot;">​</a></h3><p><strong>群創（3481）</strong>：</p><ul><li>全球最大 G3.5 FOPLP 面板（620mm × 750mm）</li><li><strong>2025 年開始量產出貨</strong>，面積約為傳統 300mm 晶圓的 7 倍</li><li>提供 RDL 基板及玻璃核心基板（GCS）給大 AI/2.5D 封裝客戶</li><li><strong>營收貢獻度預估（2026）</strong>：FOPLP 相關佔比約 <strong>3-5%</strong></li></ul><p><strong>友達（2409）</strong>：</p><ul><li>利用面板製造經驗切入 FOPLP，與玻璃基板技術融合中</li><li><strong>營收貢獻度預估（2026）</strong>：FOPLP 相關佔比約 <strong>1-3%</strong></li></ul><hr><h2 id="三、台積電-2330-—-核心推動者-⭐⭐⭐⭐⭐" tabindex="-1">三、台積電（2330）— 核心推動者 ⭐⭐⭐⭐⭐ <a class="header-anchor" href="#三、台積電-2330-—-核心推動者-⭐⭐⭐⭐⭐" aria-label="Permalink to &quot;三、台積電（2330）— 核心推動者 ⭐⭐⭐⭐⭐&quot;">​</a></h2><p><strong>定位</strong>：玻璃基板技術最積極的晶圓代工廠，CoPoS 技術推動者</p><p><strong>最新進展（2026年5月）</strong>：</p><ul><li>積極推進 <strong>CoPoS（Chip-on-Panel-on-Substrate）</strong> 技術</li><li><strong>2026 年計畫建成迷你產線</strong>（試產規模）</li><li>預計 <strong>2028 年導入玻璃基板量產</strong></li><li>加速推進玻璃基板與 FOPLP 融合</li></ul><p><strong>營收貢獻度預估（2026）</strong>：</p><ul><li>玻璃基板相關佔台積電總營收 <strong>&lt;1%</strong>（目前以矽基先進製程為主）</li><li>2028 年量產後，預估可提升至 <strong>3-5%</strong></li></ul><hr><h2 id="四、成長動能排序-2026-2028" tabindex="-1">四、成長動能排序（2026-2028） <a class="header-anchor" href="#四、成長動能排序-2026-2028" aria-label="Permalink to &quot;四、成長動能排序（2026-2028）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">排名</th><th>公司</th><th>玻璃基板相關性</th><th>短期（2026）營收佔比</th><th>中期（2028）預估佔比</th><th>投資推薦等級</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td><strong>鈦昇（8027）</strong></td><td>⭐⭐⭐⭐⭐</td><td>15-25%</td><td>30-40%</td><td>🟢 首選</td></tr><tr><td style="text-align:center;">2</td><td><strong>群翊（6664）</strong></td><td>⭐⭐⭐⭐⭐</td><td>10-20%</td><td>25-35%</td><td>🟢 首選</td></tr><tr><td style="text-align:center;">3</td><td><strong>欣興（3037）</strong></td><td>⭐⭐⭐⭐⭐</td><td>5-8%</td><td>15-25%</td><td>🟡 推薦</td></tr><tr><td style="text-align:center;">4</td><td><strong>台玻（1802）</strong></td><td>⭐⭐⭐⭐⭐</td><td>3-5%</td><td>8-12%</td><td>🟡 推薦</td></tr><tr><td style="text-align:center;">5</td><td><strong>群創（3481）</strong></td><td>⭐⭐⭐⭐</td><td>3-5%</td><td>8-15%</td><td>🟡 推薦</td></tr><tr><td style="text-align:center;">6</td><td><strong>南電（8046）</strong></td><td>⭐⭐⭐⭐</td><td>3-5%</td><td>8-12%</td><td>🟢 推薦</td></tr><tr><td style="text-align:center;">7</td><td><strong>景碩（3189）</strong></td><td>⭐⭐⭐⭐</td><td>3-5%</td><td>8-12%</td><td>🟡 推薦</td></tr><tr><td style="text-align:center;">8</td><td><strong>日月光投控（3711）</strong></td><td>⭐⭐⭐</td><td>2-3%</td><td>5-10%</td><td>🟢 推薦</td></tr><tr><td style="text-align:center;">9</td><td><strong>台積電（2330）</strong></td><td>⭐⭐⭐⭐⭐</td><td>&lt;1%</td><td>3-5%</td><td>🟡 推薦</td></tr><tr><td style="text-align:center;">10</td><td><strong>友達（2409）</strong></td><td>⭐⭐⭐</td><td>1-3%</td><td>3-8%</td><td>🟡 觀望</td></tr><tr><td style="text-align:center;">11</td><td><strong>悅城（6405）</strong></td><td>⭐⭐⭐</td><td>&lt;1%</td><td>已轉型</td><td>🔴 不推薦</td></tr></tbody></table><hr><h2 id="五、主要風險因素-台股角度" tabindex="-1">五、主要風險因素（台股角度） <a class="header-anchor" href="#五、主要風險因素-台股角度" aria-label="Permalink to &quot;五、主要風險因素（台股角度）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>風險</th><th>影響範圍</th><th>嚴重度</th></tr></thead><tbody><tr><td><strong>量產延遲</strong></td><td>所有台廠，尤其載板製造商</td><td>⚠️⚠️⚠️</td></tr><tr><td><strong>良率瓶頸</strong></td><td>鈦昇、群翊等設備商出貨延後</td><td>⚠️⚠️⚠️</td></tr><tr><td><strong>T-Glass 短缺</strong></td><td>台玻、南電、景碩等載板廠</td><td>⚠️⚠️</td></tr><tr><td><strong>中國競爭</strong></td><td>京東方、Visionox 以國家補貼壓低價格</td><td>⚠️⚠️</td></tr><tr><td><strong>客戶集中</strong></td><td>鈦昇（Intel）、欣興（Intel/NVIDIA）</td><td>⚠️⚠️</td></tr><tr><td><strong>ABF 反撲</strong></td><td>所有載板廠，玻璃替代時程可能延後</td><td>⚠️</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>Digitimes (2026-04): 玻璃基板供應鏈相關報導</li><li>TechNews (2026-03): 群翊 2025 Q4 財報分析</li><li>Cheetah News / China Times (2026-04): 台股玻璃基板概念股系列報導</li><li>Pocket.tw (2026-05): 玻璃基板台股供應鏈深度分析</li><li>Sinotrade (2026-04): GCS 和 TGV 技術解析</li><li>UDN Financial (2025-2026): 南電、景碩相關報導</li><li>TPCA (2026): 台灣 PCB 協會玻璃基板產業報告</li></ol>',104)])])}const c=r(o,[["render",s]]);export{u as __pageData,c as default};
